	getRawDirectory(): string {
		return join(this.baseDir, this.config.directory);
	}

	/**
	 * 检查结果是否需要存储到 raw 目录
	 */
	shouldStoreRaw(result: unknown): boolean {
		if (!this.config.enabled) return false;

		const size = this.estimateSize(result);
		return size > this.config.thresholdBytes;
	}

	/**
	 * 估算结果大小（字节）
	 */
	private estimateSize(result: unknown): number {
		try {
			const json = JSON.stringify(result);
			return Buffer.byteLength(json, "utf8");
		} catch {
			return 0;
		}
	}

	/**
	 * 存储结果到 raw 目录
	 * @param toolCallId tool call ID
	 * @param result 要存储的结果
	 * @returns 文件引用路径（相对于 session 目录）
	 */
	storeResult(toolCallId: string, result: unknown): string | null {
		if (!this.config.enabled) return null;

		try {
			const filename = `${toolCallId}.json`;
			const filepath = join(this.getRawDirectory(), filename);

			const data = JSON.stringify(result, null, 2);
			writeFileSync(filepath, data, "utf8");

			// 返回相对于 baseDir 的路径
			return join(this.config.directory, filename);
		} catch (error) {
			console.error(`Failed to store raw result for ${toolCallId}:`, error);
			return null;
		}
	}

	/**
	 * 读取 raw 结果
	 * @param ref 文件引用路径
	 * @returns 存储的结果
	 */
	readResult(ref: string): unknown | null {
		try {
			const filepath = join(this.baseDir, ref);
			const data = readFileSync(filepath, "utf8");
			return JSON.parse(data);
		} catch (error) {
			console.error(`Failed to read raw result from ${ref}:`, error);
			return null;
		}
	}

	/**
	 * 获取配置
	 */
	getConfig(): RawResultStorageConfig {
		return { ...this.config };
	}
}

/**
 * 创建 RawStorageManager 实例
 */
export function createRawStorageManager(
	baseDir: string,
	config?: Partial<RawResultStorageConfig>
): RawStorageManager {
	return new RawStorageManager(baseDir, config);
}

